flowchartDiagram.code:
flowchart TD
  StartProcess["Start XRT Operational Sequence"] --> Initialize("Initialize XEP & CCD");
  Initialize --> PowerOn{"Power On TAM?"};
  PowerOn -- Yes --> TAMOn["Activate TAM Power"];
  TAMOn --> CommTAM["Establish TAM Communication"];
