  SkipTAM --> SlewCmd["Receive Slew Command"];
  CommTAM --> SlewCmd;
  SlewCmd --> CheckDoor{"Camera Door Closed?"};
  CheckDoor -- Yes --> OpenDoor["Open Camera Door"];
  CheckDoor -- No --> ErrorDoor("Door Already Open Error");
  ErrorDoor --> MonitorErrors["Monitor & Report Errors"];
  OpenDoor --> ConfigCCD["Configure CCD Mode"];
  ConfigCCD --> BeginObs["Begin Science Observation"];
  BeginObs --> CollectData["Collect CCD Science Data"];
  CollectData --> CompressData["Compress Data"];
  CompressData --> SendTelemetry["Send Telemetry to S/C"];
  SendTelemetry --> TempControl{"Manage Thermals?"};
  TempControl -- Yes --> TECadjust["Adjust TEC & Heaters"];
  TECadjust --> EndLoop(Loop);
  TempControl -- No --> EndLoop(Loop);
  EndLoop --> ContinueObs{"Continue Observation?"};
  ContinueObs -- Yes --> CollectData;
  ContinueObs -- No --> PowerOff["Power Off XRT"];
  PowerOff --> EndSequence["End Operational Sequence"];

